import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import './SettingsPage.css';

const DEFAULT_SETTINGS = {
  notifications: true,
  autoplayVideo: false,
  showAdult: true,
  language: 'en'
};

const SettingsPage = () => {
  const { user } = useAuth();
  const [settings, setSettings] = useState(DEFAULT_SETTINGS);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    if (!user) return;
    const fromStorage = localStorage.getItem(`mangauz_settings_${user.id}`);
    if (fromStorage) {
      setSettings(JSON.parse(fromStorage));
    }
  }, [user]);

  const updateField = (key, value) => {
    setSaved(false);
    setSettings((prev) => ({ ...prev, [key]: value }));
  };

  const handleSave = () => {
    if (!user) return;
    localStorage.setItem(`mangauz_settings_${user.id}`, JSON.stringify(settings));
    setSaved(true);
  };

  if (!user) {
    return (
      <div className="settings-page">
        <h2>Login required</h2>
        <p>You need to sign in to manage settings.</p>
      </div>
    );
  }

  return (
    <div className="settings-page">
      <div className="settings-header">
        <h1>Settings</h1>
        <p>Manage your account preferences.</p>
      </div>

      <div className="settings-card">
        <label className="setting-row">
          <span>Enable notifications</span>
          <input
            type="checkbox"
            checked={settings.notifications}
            onChange={(e) => updateField('notifications', e.target.checked)}
          />
        </label>

        <label className="setting-row">
          <span>Autoplay videos</span>
          <input
            type="checkbox"
            checked={settings.autoplayVideo}
            onChange={(e) => updateField('autoplayVideo', e.target.checked)}
          />
        </label>

        <label className="setting-row">
          <span>Show 18+ content</span>
          <input
            type="checkbox"
            checked={settings.showAdult}
            onChange={(e) => updateField('showAdult', e.target.checked)}
          />
        </label>

        <label className="setting-row">
          <span>Language</span>
          <select value={settings.language} onChange={(e) => updateField('language', e.target.value)}>
            <option value="en">English</option>
            <option value="uz">Uzbek</option>
            <option value="ru">Russian</option>
          </select>
        </label>

        <button className="save-settings-btn" onClick={handleSave}>
          Save settings
        </button>
        {saved && <p className="saved-note">Saved successfully.</p>}
      </div>
    </div>
  );
};

export default SettingsPage;
